import{_ as e,c as o,o as i,ae as l}from"./chunks/framework.D4x4JNJ3.js";const m=JSON.parse('{"title":"版本更新日志 v2026.2.x","description":"","frontmatter":{"title":"版本更新日志 v2026.2.x"},"headers":[],"relativePath":"zh/changelog/v2026.2.x.md","filePath":"zh/changelog/v2026.2.x.md","lastUpdated":1772161383000}'),t={name:"zh/changelog/v2026.2.x.md"};function n(r,a,s,c,d,g){return i(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="mogan-stem-v2026-2-x-版本更新日志" tabindex="-1">Mogan STEM v2026.2.x 版本更新日志 <a class="header-anchor" href="#mogan-stem-v2026-2-x-版本更新日志" aria-label="Permalink to “Mogan STEM v2026.2.x 版本更新日志”">​</a></h1><blockquote><p>说明：Liii STEM 是 Mogan STEM 的商业版，会在开源版的基础上提供账号登录、AI 等增值能力。更多细节见 Liii STEM：<a href="https://liiistem.cn/docs/changelog-v2026.1.x.html" target="_blank" rel="">v2026.1.x</a></p></blockquote><h2 id="⭐️-全新功能和亮点" tabindex="-1">⭐️ 全新功能和亮点 <a class="header-anchor" href="#⭐️-全新功能和亮点" aria-label="Permalink to “⭐️ 全新功能和亮点”">​</a></h2><ol><li><strong>三线表</strong>：新增三线表（<code>插入</code> -&gt; <code>表格</code> -&gt; <code>三线表</code>），更适合学术排版。</li><li><strong>LaTeX 导入增强</strong>：修复分段函数等复杂结构导入时的排版错位问题。</li><li><strong>图片交互</strong>：支持鼠标缩放图片，编辑更直观。</li><li><strong>符号输入增强</strong>：新增 <code>/ /</code> 的乐高符号。</li><li><strong>数学补全更稳定</strong>：修复 Tab Cycling 弹窗定位错误，缩放/布局变化下更可靠。</li><li><strong>Windows 导入导出一致性</strong>：优先使用内置 Pandoc，减少环境差异带来的问题。</li><li><strong>插件稳定性</strong>：修复 <code>sympy.symbol</code> 引发的 Python 插件报错；移除可能导致软件卡死的不完整 Octave 插件。</li><li><strong>细节优化</strong>：调整打开 PDF 弹窗界面；打开已有文件时，移除标题栏多余出现的“无标题文件”。</li></ol><h2 id="🌟-总结" tabindex="-1">🌟 总结 <a class="header-anchor" href="#🌟-总结" aria-label="Permalink to “🌟 总结”">​</a></h2><p>Mogan 2.0（v2026.2.x）聚焦于 <strong>表格与导入导出</strong> 体验与 <strong>插件稳定性</strong>：新增三线表，修复 LaTeX 导入分段函数错位问题，并在 Windows 下默认使用内置 Pandoc；同时修复/清理影响稳定性的插件问题，完善 Tab Cycling 与若干界面细节。商业版 Liii STEM 在此基础上提供 AI 等增值能力。</p><h2 id="🔧-更新日志" tabindex="-1">🔧 更新日志 <a class="header-anchor" href="#🔧-更新日志" aria-label="Permalink to “🔧 更新日志”">​</a></h2><h3 id="mogan-stem-v2026-2-0-2026-02-13" tabindex="-1">Mogan STEM v2026.2.0 (2026/02/13) <a class="header-anchor" href="#mogan-stem-v2026-2-0-2026-02-13" aria-label="Permalink to “Mogan STEM v2026.2.0 (2026/02/13)”">​</a></h3><ol><li>（Liii STEM）<strong>AI</strong> 新增 GLM-4.6V 和 Kimi-K2.5 大模型。</li><li>表格类型新增三线表，新增 <code>插入</code> -&gt; <code>表格</code> -&gt; <code>三线表</code> 选项。</li><li>图片支持通过鼠标缩放。</li><li>添加 <code>/ /</code> 的乐高符号。</li><li>修复数学补全 Tab Cycling 弹窗位置参考错误。</li><li>修复 LaTeX 导入分段函数排版错位。</li><li>调整打开 PDF 弹窗界面。</li><li>Windows 下优先使用软件自带 Pandoc。</li><li>修复 <code>sympy.symbol</code> 导致的 Python 插件报错。</li><li>删除会导致软件卡死的不完整 Octave 插件。</li><li>打开已有文件时，移除标题栏额外出现的“无标题文件”。</li></ol><h2 id="👏-加入社区" tabindex="-1">👏 加入社区 <a class="header-anchor" href="#👏-加入社区" aria-label="Permalink to “👏 加入社区”">​</a></h2><ul><li>墨干社区 QQ 群：934456971</li><li>Discord 群组：<a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li><li>官网：<a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li></ul>',11)])])}const p=e(t,[["render",n]]);export{m as __pageData,p as default};
